"use client";

import {
  ToolUIErrorBoundary,
  type ToolUIErrorBoundaryProps,
} from "../shared/error-boundary";

export function ProgressTrackerErrorBoundary(
  props: Omit<ToolUIErrorBoundaryProps, "componentName">,
) {
  const { children, ...rest } = props;
  return (
    <ToolUIErrorBoundary componentName="ProgressTracker" {...rest}>
      {children}
    </ToolUIErrorBoundary>
  );
}

export { ProgressTracker } from "./progress-tracker";
export { ProgressTrackerErrorBoundary } from "./error-boundary";
export {
  SerializableProgressTrackerSchema,
  parseSerializableProgressTracker,
  safeParseSerializableProgressTracker,
  ProgressStepSchema,
  type SerializableProgressTracker,
  type ProgressTrackerProps,
  type ProgressTrackerChoice,
  type ProgressStep,
} from "./schema";

"use client";

import * as React from "react";
import { cn } from "./_adapter";
import type { ProgressTrackerProps } from "./schema";
import { ActionButtons } from "../shared/action-buttons";
import { normalizeActionsConfig } from "../shared/actions-config";
import type { Action } from "../shared/schema";
import { Check, X, Loader2, Timer, AlertCircle } from "lucide-react";

function formatElapsedTime(milliseconds: number): string {
  const seconds = milliseconds / 1000;

  if (seconds < 60) {
    return `${seconds.toFixed(1)}s`;
  }

  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = Math.floor(seconds % 60);
  return `${minutes}m ${remainingSeconds}s`;
}

interface StepIndicatorProps {
  status: "pending" | "in-progress" | "completed" | "failed";
}

function StepIndicator({ status }: StepIndicatorProps) {
  if (status === "pending") {
    return (
      <span
        className="bg-card border-border flex size-6 shrink-0 items-center justify-center rounded-full border motion-safe:transition-all motion-safe:duration-200"
        aria-hidden="true"
      />
    );
  }

  if (status === "in-progress") {
    return (
      <span
        className="bg-card border-border flex size-6 shrink-0 items-center justify-center rounded-full border shadow-[0_0_0_4px_hsl(var(--primary)/0.1)] motion-safe:transition-all motion-safe:duration-300"
        aria-hidden="true"
      >
        <Loader2 className="text-primary size-5 motion-safe:animate-[spin_0.7s_linear_infinite]" />
      </span>
    );
  }

  if (status === "completed") {
    return (
      <span
        className="bg-primary text-primary-foreground border-primary flex size-6 shrink-0 items-center justify-center rounded-full border shadow-sm motion-safe:animate-[spring-bounce_500ms_cubic-bezier(0.34,1.56,0.64,1)]"
        aria-hidden="true"
      >
        <Check
          className="size-4 [&_path]:motion-safe:animate-[check-draw_400ms_cubic-bezier(0.34,1.56,0.64,1)_100ms_backwards]"
          strokeWidth={3}
          style={{
            ["--check-path-length" as string]: "24",
          }}
        />
      </span>
    );
  }

  if (status === "failed") {
    return (
      <span
        className="bg-destructive border-destructive flex size-6 shrink-0 items-center justify-center rounded-full border text-white shadow-sm motion-safe:animate-[spring-bounce_500ms_cubic-bezier(0.34,1.56,0.64,1)] dark:border-red-600 dark:bg-red-600"
        aria-hidden="true"
      >
        <X
          className="size-4 [&_path]:motion-safe:animate-[check-draw_400ms_cubic-bezier(0.34,1.56,0.64,1)_100ms_backwards]"
          strokeWidth={3}
          style={{
            ["--check-path-length" as string]: "16",
          }}
        />
      </span>
    );
  }

  return null;
}

export function ProgressTracker({
  id,
  steps,
  elapsedTime,
  responseActions,
  onResponseAction,
  onBeforeResponseAction,
  className,
  choice,
}: ProgressTrackerProps) {
  const hasInProgress = steps.some((step) => step.status === "in-progress");
  const hasFailed = steps.some((step) => step.status === "failed");
  const allCompleted = steps.every((step) => step.status === "completed");

  const currentStepId = React.useMemo(() => {
    const inProgressStep = steps.find((s) => s.status === "in-progress");
    if (inProgressStep) return inProgressStep.id;

    const firstPendingStep = steps.find((s) => s.status === "pending");
    if (firstPendingStep) return firstPendingStep.id;

    return null;
  }, [steps]);

  const handleAction = React.useCallback(
    async (actionId: string) => {
      await onResponseAction?.(actionId);
    },
    [onResponseAction],
  );

  const defaultActions: Action[] = React.useMemo(
    () => [
      {
        id: "cancel",
        label: "Cancel",
        variant: "outline",
      },
    ],
    [],
  );

  const normalizedActions = React.useMemo(() => {
    if (allCompleted || choice) return null;

    const config = normalizeActionsConfig(responseActions);
    if (config) return config;

    if (hasFailed) return null;

    return {
      items: defaultActions,
      align: "right" as const,
    };
  }, [allCompleted, choice, responseActions, hasFailed, defaultActions]);

  const viewKey = choice ? `receipt-${choice.outcome}` : "interactive";
  const receiptOutcome = choice?.outcome;
  const receiptSummary = choice?.summary;
  const isReceiptSuccess = receiptOutcome === "success";
  const isReceiptFailed = receiptOutcome === "failed";

  return (
    <div key={viewKey} className="contents">
      {choice ? (
        <div
          className={cn(
            "flex w-full max-w-md min-w-80 flex-col",
            "text-foreground select-none",
            "motion-safe:animate-[fade-blur-in_300ms_cubic-bezier(0.16,1,0.3,1)_both]",
            className,
          )}
          data-slot="progress-tracker"
          data-tool-ui-id={id}
          data-receipt="true"
          role="status"
          aria-label={receiptSummary}
        >
          <div className="bg-card/60 flex w-full flex-col gap-4 rounded-2xl border p-5 shadow-xs">
            <div className="flex items-center justify-between">
              {elapsedTime !== undefined && elapsedTime > 0 && (
                <div className="text-muted-foreground flex items-center gap-1.5 font-mono text-xs">
                  <Timer className="-mt-px size-3.5" />
                  <span>{formatElapsedTime(elapsedTime)}</span>
                </div>
              )}
              <span
                className={cn(
                  "flex items-center gap-1.5 text-xs font-medium",
                  isReceiptSuccess && "text-emerald-600 dark:text-emerald-500",
                  isReceiptFailed && "text-destructive",
                  !isReceiptSuccess &&
                    !isReceiptFailed &&
                    "text-muted-foreground",
                )}
              >
                {isReceiptSuccess ? (
                  <Check className="size-3.5" />
                ) : isReceiptFailed ? (
                  <AlertCircle className="size-3.5" />
                ) : (
                  <Check className="size-3.5" />
                )}
                {receiptSummary}
              </span>
            </div>

            <ul role="list" className="flex flex-col gap-2">
              {steps.map((step, index) => (
                <li
                  key={step.id}
                  className="relative -mx-2 flex items-start gap-3 rounded-lg px-2 py-1.5"
                >
                  {index < steps.length - 1 && (
                    <div
                      className="bg-border absolute top-8 left-5 w-px"
                      style={{
                        height: "calc(100% + 0.5rem)",
                      }}
                      aria-hidden="true"
                    />
                  )}
                  <div className="relative z-10">
                    <StepIndicator status={step.status} />
                  </div>
                  <div className="flex flex-1 flex-col gap-0.5">
                    <span className="text-sm leading-6 font-medium">
                      {step.label}
                    </span>
                    {step.description && (
                      <span className="text-muted-foreground text-sm">
                        {step.description}
                      </span>
                    )}
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      ) : (
        <article
          className={cn(
            "flex w-full max-w-md min-w-80 flex-col gap-3",
            "text-foreground select-none",
            className,
          )}
          data-slot="progress-tracker"
          data-tool-ui-id={id}
          role="status"
          aria-live="polite"
          aria-busy={hasInProgress}
        >
          <div className="bg-card flex w-full flex-col gap-4 rounded-2xl border p-5 shadow-xs">
            {elapsedTime !== undefined && elapsedTime > 0 && (
              <div className="text-muted-foreground flex items-center gap-1.5 font-mono text-xs">
                <Timer className="-mt-px size-3.5" />
                <span>{formatElapsedTime(elapsedTime)}</span>
              </div>
            )}

            <ul role="list" className="flex flex-col gap-3">
              {steps.map((step, index) => {
                const isCurrent = step.id === currentStepId;
                const isActive = step.status === "in-progress";
                const hasDescription = !!step.description;

                return (
                  <li
                    key={step.id}
                    className="relative -mx-2"
                    aria-current={isCurrent ? "step" : undefined}
                  >
                    {index < steps.length - 1 && (
                      <div
                        className={cn(
                          "bg-border absolute top-6 left-5 w-px",
                          "motion-safe:transition-all motion-safe:duration-300",
                        )}
                        style={{
                          height: "calc(100% + 0.25rem)",
                        }}
                        aria-hidden="true"
                      />
                    )}
                    <div
                      className={cn(
                        "relative z-10 flex items-start gap-3 rounded-lg px-2 py-1.5",
                        "motion-safe:transition-all motion-safe:duration-300",
                        isCurrent && "bg-primary/5",
                      )}
                      style={{
                        backdropFilter: isCurrent ? "blur(2px)" : undefined,
                      }}
                    >
                      <div className="relative z-10">
                        <StepIndicator status={step.status} />
                      </div>
                      <div className="flex flex-1 flex-col">
                        <span
                          className={cn(
                            "text-sm leading-6 font-medium",
                            step.status === "pending" &&
                              "text-muted-foreground",
                            step.status === "in-progress" &&
                              "motion-safe:shimmer shimmer-invert text-foreground",
                          )}
                        >
                          {step.label}
                        </span>
                        {hasDescription && (
                          <div
                            className={cn(
                              "grid motion-safe:transition-[grid-template-rows,opacity] motion-safe:duration-300 motion-safe:ease-out",
                              isActive
                                ? "grid-rows-[1fr] opacity-100"
                                : "grid-rows-[0fr] opacity-0",
                            )}
                          >
                            <div className="overflow-hidden">
                              <span className="text-muted-foreground block pt-0.5 text-sm">
                                {step.description}
                              </span>
                            </div>
                          </div>
                        )}
                      </div>
                    </div>
                  </li>
                );
              })}
            </ul>
          </div>

          {normalizedActions && (
            <div className="@container/actions">
              <ActionButtons
                actions={normalizedActions.items}
                align={normalizedActions.align}
                confirmTimeout={normalizedActions.confirmTimeout}
                onAction={handleAction}
                onBeforeAction={onBeforeResponseAction}
              />
            </div>
          )}
        </article>
      )}
    </div>
  );
}

import { z } from "zod";
import {
  ToolUISurfaceSchema,
  ToolUIReceiptSchema,
  SerializableActionSchema,
  SerializableActionsConfigSchema,
  type ToolUIReceipt,
} from "../shared/schema";
import { parseWithSchema, safeParseWithSchema } from "../shared/parse";
import type { ActionsProp } from "../shared/actions-config";

/**
 * Receipt state for ProgressTracker showing the outcome of a workflow.
 */
export type ProgressTrackerChoice = ToolUIReceipt;

export const ProgressStepSchema = z.object({
  id: z.string().min(1),
  label: z.string().min(1),
  description: z.string().optional(),
  status: z.enum(["pending", "in-progress", "completed", "failed"]),
});

export type ProgressStep = z.infer<typeof ProgressStepSchema>;

export const SerializableProgressTrackerSchema = ToolUISurfaceSchema.extend({
  steps: z.array(ProgressStepSchema).min(1),
  elapsedTime: z.number().optional(),
  /**
   * When set, renders the component in receipt state showing the workflow outcome.
   */
  choice: ToolUIReceiptSchema.optional(),
  responseActions: z
    .union([z.array(SerializableActionSchema), SerializableActionsConfigSchema])
    .optional(),
});

export type SerializableProgressTracker = z.infer<
  typeof SerializableProgressTrackerSchema
>;

export function parseSerializableProgressTracker(
  input: unknown,
): SerializableProgressTracker {
  return parseWithSchema(
    SerializableProgressTrackerSchema,
    input,
    "ProgressTracker",
  );
}

export function safeParseSerializableProgressTracker(
  input: unknown,
): SerializableProgressTracker | null {
  return safeParseWithSchema(SerializableProgressTrackerSchema, input);
}

export interface ProgressTrackerProps extends SerializableProgressTracker {
  className?: string;
  responseActions?: ActionsProp;
  onResponseAction?: (actionId: string) => void | Promise<void>;
  onBeforeResponseAction?: (actionId: string) => boolean | Promise<boolean>;
}

"use client";

import type { Action } from "./schema";
import { cn, Button } from "./_adapter";
import { useActionButtons } from "./use-action-buttons";

export interface ActionButtonsProps {
  actions: Action[];
  onAction: (actionId: string) => void | Promise<void>;
  onBeforeAction?: (actionId: string) => boolean | Promise<boolean>;
  confirmTimeout?: number;
  align?: "left" | "center" | "right";
  className?: string;
}

export function ActionButtons({
  actions,
  onAction,
  onBeforeAction,
  confirmTimeout = 3000,
  align = "right",
  className,
}: ActionButtonsProps) {
  const { actions: resolvedActions, runAction } = useActionButtons({
    actions,
    onAction,
    onBeforeAction,
    confirmTimeout,
  });

  return (
    <div
      className={cn(
        "flex flex-col gap-3",
        "@sm/actions:flex-row @sm/actions:flex-wrap @sm/actions:items-center @sm/actions:gap-2",
        align === "left" && "@sm/actions:justify-start",
        align === "center" && "@sm/actions:justify-center",
        align === "right" && "@sm/actions:justify-end",
        className,
      )}
    >
      {resolvedActions.map((action) => {
        const label = action.currentLabel;
        const variant = action.variant || "default";

        return (
          <Button
            key={action.id}
            variant={variant}
            onClick={() => runAction(action.id)}
            disabled={action.isDisabled}
            className={cn(
              "rounded-full px-4!",
              "justify-center",
              "min-h-11 w-full text-base",
              "@sm/actions:min-h-0 @sm/actions:w-auto @sm/actions:px-3 @sm/actions:py-2 @sm/actions:text-sm",
              action.isConfirming &&
                "ring-destructive ring-2 ring-offset-2 motion-safe:animate-pulse",
            )}
            aria-label={
              action.shortcut ? `${label} (${action.shortcut})` : label
            }
          >
            {action.isLoading && (
              <svg
                className="mr-2 h-4 w-4 motion-safe:animate-spin"
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
              >
                <circle
                  className="opacity-25"
                  cx="12"
                  cy="12"
                  r="10"
                  stroke="currentColor"
                  strokeWidth="4"
                />
                <path
                  className="opacity-75"
                  fill="currentColor"
                  d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                />
              </svg>
            )}
            {action.icon && !action.isLoading && (
              <span className="mr-2">{action.icon}</span>
            )}
            {label}
            {action.shortcut && !action.isLoading && (
              <kbd className="border-border bg-muted ml-2.5 hidden rounded-lg border px-2 py-0.5 font-mono text-xs font-medium sm:inline-block">
                {action.shortcut}
              </kbd>
            )}
          </Button>
        );
      })}
    </div>
  );
}

import type { Action, ActionsConfig } from "./schema";

export type ActionsProp = ActionsConfig | Action[];

const NEGATORY_ACTION_IDS = new Set([
  "cancel",
  "dismiss",
  "skip",
  "no",
  "reset",
  "close",
  "decline",
  "reject",
  "back",
  "later",
  "not-now",
  "maybe-later",
]);

function inferVariant(action: Action): Action {
  if (action.variant) return action;
  if (NEGATORY_ACTION_IDS.has(action.id)) {
    return { ...action, variant: "ghost" };
  }
  return action;
}

export function normalizeActionsConfig(
  actions?: ActionsProp,
): ActionsConfig | null {
  if (!actions) return null;

  const rawItems = Array.isArray(actions) ? actions : (actions.items ?? []);

  if (rawItems.length === 0) {
    return null;
  }

  const items = rawItems.map(inferVariant);

  return Array.isArray(actions)
    ? { items }
    : {
        items,
        align: actions.align,
        confirmTimeout: actions.confirmTimeout,
      };
}

"use client";

import * as React from "react";

export interface ToolUIErrorBoundaryProps {
  componentName: string;
  children: React.ReactNode;
  fallback?: React.ReactNode;
  onError?: (error: Error, errorInfo: React.ErrorInfo) => void;
}

interface ToolUIErrorBoundaryState {
  hasError: boolean;
  error?: Error;
}

export class ToolUIErrorBoundary extends React.Component<
  ToolUIErrorBoundaryProps,
  ToolUIErrorBoundaryState
> {
  constructor(props: ToolUIErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): ToolUIErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error(`[${this.props.componentName}] render error:`, error, errorInfo);
    this.props.onError?.(error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        this.props.fallback ?? (
          <div className="border-destructive text-destructive rounded-lg border p-4">
            <p className="font-semibold">
              {this.props.componentName} failed to render
            </p>
            <p className="text-sm">{this.state.error?.message}</p>
          </div>
        )
      );
    }
    return this.props.children;
  }
}

import { z } from "zod";

function formatZodPath(path: Array<string | number | symbol>): string {
  if (path.length === 0) return "root";
  return path
    .map((segment) =>
      typeof segment === "number" ? `[${segment}]` : String(segment),
    )
    .join(".");
}

/**
 * Format Zod errors into a compact `path: message` string.
 */
export function formatZodError(error: z.ZodError): string {
  const parts = error.issues.map((issue) => {
    const path = formatZodPath(issue.path);
    return `${path}: ${issue.message}`;
  });

  return Array.from(new Set(parts)).join("; ");
}

/**
 * Parse unknown input and throw a readable error.
 */
export function parseWithSchema<T>(
  schema: z.ZodType<T>,
  input: unknown,
  name: string,
): T {
  const res = schema.safeParse(input);
  if (!res.success) {
    throw new Error(`Invalid ${name} payload: ${formatZodError(res.error)}`);
  }
  return res.data;
}

/**
 * Parse unknown input, returning `null` instead of throwing on failure.
 *
 * Use this in assistant-ui `render` functions where `args` stream in
 * incrementally and may be incomplete until the tool call finishes.
 */
export function safeParseWithSchema<T>(
  schema: z.ZodType<T>,
  input: unknown,
): T | null {
  const res = schema.safeParse(input);
  return res.success ? res.data : null;
}

import { z } from "zod";
import type { ReactNode } from "react";

/**
 * Tool UI conventions:
 * - Serializable schemas are JSON-safe (no callbacks/ReactNode/`className`).
 * - Schema: `SerializableXSchema`
 * - Parser: `parseSerializableX(input: unknown)` (throws on invalid)
 * - Safe parser: `safeParseSerializableX(input: unknown)` (returns `null` on invalid)
 * - Actions: `responseActions`, `onResponseAction`, `onBeforeResponseAction`
 * - Root attrs: `data-tool-ui-id` + `data-slot`
 */

/**
 * Schema for tool UI identity.
 *
 * Every tool UI should have a unique identifier that:
 * - Is stable across re-renders
 * - Is meaningful (not auto-generated)
 * - Is unique within the conversation
 *
 * Format recommendation: `{component-type}-{semantic-identifier}`
 * Examples: "data-table-expenses-q3", "option-list-deploy-target"
 */
export const ToolUIIdSchema = z.string().min(1);

export type ToolUIId = z.infer<typeof ToolUIIdSchema>;

/**
 * Primary role of a Tool UI surface in a chat context.
 */
export const ToolUIRoleSchema = z.enum([
  "information",
  "decision",
  "control",
  "state",
  "composite",
]);

export type ToolUIRole = z.infer<typeof ToolUIRoleSchema>;

export const ToolUIReceiptOutcomeSchema = z.enum([
  "success",
  "partial",
  "failed",
  "cancelled",
]);

export type ToolUIReceiptOutcome = z.infer<typeof ToolUIReceiptOutcomeSchema>;

/**
 * Optional receipt metadata: a durable summary of an outcome.
 */
export const ToolUIReceiptSchema = z.object({
  outcome: ToolUIReceiptOutcomeSchema,
  summary: z.string().min(1),
  identifiers: z.record(z.string(), z.string()).optional(),
  at: z.string().datetime(),
});

export type ToolUIReceipt = z.infer<typeof ToolUIReceiptSchema>;

/**
 * Base schema for Tool UI payloads (id + optional role/receipt).
 */
export const ToolUISurfaceSchema = z.object({
  id: ToolUIIdSchema,
  role: ToolUIRoleSchema.optional(),
  receipt: ToolUIReceiptSchema.optional(),
});

export type ToolUISurface = z.infer<typeof ToolUISurfaceSchema>;

export const ActionSchema = z.object({
  id: z.string().min(1),
  label: z.string().min(1),
  /**
   * Canonical narration the assistant can use after this action is taken.
   *
   * Example: "I exported the table as CSV." / "I opened the link in a new tab."
   */
  sentence: z.string().optional(),
  confirmLabel: z.string().optional(),
  variant: z
    .enum(["default", "destructive", "secondary", "ghost", "outline"])
    .optional(),
  icon: z.custom<ReactNode>().optional(),
  loading: z.boolean().optional(),
  disabled: z.boolean().optional(),
  shortcut: z.string().optional(),
});

export type Action = z.infer<typeof ActionSchema>;

export const ActionButtonsPropsSchema = z.object({
  actions: z.array(ActionSchema).min(1),
  align: z.enum(["left", "center", "right"]).optional(),
  confirmTimeout: z.number().positive().optional(),
  className: z.string().optional(),
});

export const SerializableActionSchema = ActionSchema.omit({ icon: true });
export const SerializableActionsSchema = ActionButtonsPropsSchema.extend({
  actions: z.array(SerializableActionSchema),
}).omit({ className: true });

export interface ActionsConfig {
  items: Action[];
  align?: "left" | "center" | "right";
  confirmTimeout?: number;
}

export const SerializableActionsConfigSchema = z.object({
  items: z.array(SerializableActionSchema).min(1),
  align: z.enum(["left", "center", "right"]).optional(),
  confirmTimeout: z.number().positive().optional(),
});

export type SerializableActionsConfig = z.infer<
  typeof SerializableActionsConfigSchema
>;

export type SerializableAction = z.infer<typeof SerializableActionSchema>;

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import type { Action } from "./schema";

export type UseActionButtonsOptions = {
  actions: Action[];
  onAction: (actionId: string) => void | Promise<void>;
  onBeforeAction?: (actionId: string) => boolean | Promise<boolean>;
  confirmTimeout?: number;
};

export type UseActionButtonsResult = {
  actions: Array<
    Action & {
      currentLabel: string;
      isConfirming: boolean;
      isExecuting: boolean;
      isDisabled: boolean;
      isLoading: boolean;
    }
  >;
  runAction: (actionId: string) => Promise<void>;
  confirmingActionId: string | null;
  executingActionId: string | null;
};

export function useActionButtons(
  options: UseActionButtonsOptions,
): UseActionButtonsResult {
  const {
    actions,
    onAction,
    onBeforeAction,
    confirmTimeout = 3000,
  } = options;

  const [confirmingActionId, setConfirmingActionId] = useState<string | null>(
    null,
  );
  const [executingActionId, setExecutingActionId] = useState<string | null>(
    null,
  );

  useEffect(() => {
    if (!confirmingActionId) return;
    const id = setTimeout(() => setConfirmingActionId(null), confirmTimeout);
    return () => clearTimeout(id);
  }, [confirmingActionId, confirmTimeout]);

  useEffect(() => {
    if (!confirmingActionId) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        setConfirmingActionId(null);
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [confirmingActionId]);

  const runAction = useCallback(
    async (actionId: string) => {
      const action = actions.find((a) => a.id === actionId);
      if (!action) return;

      const isAnyActionExecuting = executingActionId !== null;
      if (action.disabled || action.loading || isAnyActionExecuting) {
        return;
      }

      if (action.confirmLabel && confirmingActionId !== action.id) {
        setConfirmingActionId(action.id);
        return;
      }

      if (onBeforeAction) {
        const shouldProceed = await onBeforeAction(action.id);
        if (!shouldProceed) {
          setConfirmingActionId(null);
          return;
        }
      }

      try {
        setExecutingActionId(action.id);
        await onAction(action.id);
      } finally {
        setExecutingActionId(null);
        setConfirmingActionId(null);
      }
    },
    [actions, confirmingActionId, executingActionId, onAction, onBeforeAction],
  );

  const resolvedActions = useMemo(
    () =>
      actions.map((action) => {
        const isConfirming = confirmingActionId === action.id;
        const isThisActionExecuting = executingActionId === action.id;
        const isLoading = action.loading || isThisActionExecuting;
        const isDisabled =
          action.disabled || (executingActionId !== null && !isThisActionExecuting);
        const currentLabel =
          isConfirming && action.confirmLabel
            ? action.confirmLabel
            : action.label;

        return {
          ...action,
          currentLabel,
          isConfirming,
          isExecuting: isThisActionExecuting,
          isDisabled,
          isLoading,
        };
      }),
    [actions, confirmingActionId, executingActionId],
  );

  return {
    actions: resolvedActions,
    runAction,
    confirmingActionId,
    executingActionId,
  };
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
